t.script:
            document.addEventListener('DOMContentLoaded', function() {
                var map = L.map('map').setView([-30.750, -57.983], 13);

                L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
                    attribution: '© OpenStreetMap'
                }).addTo(map);

                try {
                    // Leer datos del atributo data
                    var dataElement = document.getElementById('luminarias-data');
                    var luminarias = [];
                    if (dataElement && dataElement.getAttribute('data-luminarias')) {
                        luminarias = JSON.parse(dataElement.getAttribute('data-luminarias'));
                    }

                    if (luminarias && luminarias.length > 0) {
                        luminarias.forEach(function(l){
                            if (l.lat && l.lng) {
                                L.marker([l.lat, l.lng])
                                .addTo(map)
                                .bindPopup(
                                    "<b>" + (l.name || 'Sin nombre') + "</b><br/>" +
                                    (l.direccion || '')
                                );
                            }
                        });
                    }
                } catch (e) {
                    console.error("Error cargando luminarias:", e);
                }
            });
